def briefhoofd(data):
    """Herbruikbaar briefhoofd voor pagina's 2-6"""
    return f"""
    <div class="letterhead">
        {LOGO_SVG_COLOR}
        <div class="lh-contact">
            <strong>Senior Advies</strong>
            {data['contact']['tel']}<br>
            {data['contact']['email']}<br>
            {data['contact']['web']}
        </div>
    </div>
    <div class="lh-bar"></div>
    """

def pagina_footer(tekst, pagnr=None):
    nr = f'<span style="float:right;">{pagnr}</span>' if pagnr else ""
    return f'<div class="footer">{nr}{tekst}</div>'

