# ─────────────────────────────────────────────────────────────────────────────
# GENERATOR
# ─────────────────────────────────────────────────────────────────────────────


# ─────────────────────────────────────────────────────────────────────────────
# EXCEL-INTEGRATIE
# ─────────────────────────────────────────────────────────────────────────────

NL_MAANDEN = {
    1:"januari", 2:"februari", 3:"maart", 4:"april",
    5:"mei", 6:"juni", 7:"juli", 8:"augustus",
    9:"september", 10:"oktober", 11:"november", 12:"december"
}

def nl_datum(dt):
    if dt is None: return ""
    return f"{dt.day} {NL_MAANDEN[dt.month]} {dt.year}"

def eur(val):
    """Formatteer getal als € bedrag met punten als duizendteken."""
    if val is None: return "n.b."
    return f"€ {int(round(val)):,}".replace(",", ".")

def lees_excel(excel_pad: str, rapport_id: str) -> Dict[str, Any]:
    """
    Leest één rapport-rij uit Berekening_Rapport tab.
    Geeft data-dict terug klaar voor generate_rapport().
    Excel berekent — dit script leest alleen.
    """
    wb = openpyxl.load_workbook(excel_pad, data_only=True)
    ws = wb["Berekening_Rapport"]

    # Bouw kolomnamen-index op basis van rij 2
    headers = {}
    for cell in ws[2]:
        if cell.value:
            headers[cell.value] = cell.column - 1  # 0-indexed

    def get(row_vals, key):
        idx = headers.get(key)
        if idx is None: return None
        return row_vals[idx] if idx < len(row_vals) else None

    # Zoek de juiste rij op rapport_id
    for row in ws.iter_rows(min_row=3, values_only=True):
        if row[0] != rapport_id:
            continue

        datum_raw = get(row, "timestampBerekening")
        datum = nl_datum(datum_raw) if hasattr(datum_raw, "strftime") else "—"

        return {
            "rapport_ref":     rapport_id,
            "client_name":     get(row, "naam") or "Onbekend",
            "rapport_datum":   datum,
            "besparing_jaar1": eur(get(row, "voordeel_jaar1")),
            "betaling_huidig": eur(get(row, "bijdrage_jaar1_basis")),
            "betaling_nieuw":  eur(get(row, "bijdrage_jaar1_na_advies")),
            "contact": TESTDATA["contact"],    # vaste bedrijfsgegevens
            "adviseur": TESTDATA["adviseur"],  # vaste adviseurgegevens
        }

    raise ValueError(f"Rapport-ID '{rapport_id}' niet gevonden in Excel.")

def generate_rapport(data: Dict[str, Any], output_path: str) -> None:
    html = f"""<!DOCTYPE html>
<html lang="nl">
<head>
<meta charset="UTF-8">
<title>Rapport {data['rapport_ref']}</title>
<style>{CSS_TEMPLATE}</style>
</head>
<body>
{page_cover(data)}
{page_brief(data)}
{page_savings(data)}
{page_how_comes(data)}
{page_how_to(data)}
{page_disclaimer(data)}
{page_cta(data)}
{page_back(data)}
</body>
</html>"""

    tmp = f"/tmp/{data['rapport_ref']}.html"
    with open(tmp, "w", encoding="utf-8") as f:
        f.write(html)

    HTML(filename=tmp).write_pdf(output_path, optimize_images=True, jpeg_quality=75, dpi=300)
    os.remove(tmp)
    print(f"✓ PDF: {output_path}")


if __name__ == "__main__":
    import sys

    EXCEL_PAD = "/mnt/user-data/uploads/Senior_Advies_V2.xlsx"

    # Rapport-ID meegeven als argument, anders testklant
    rapport_id = sys.argv[1] if len(sys.argv) > 1 else "RAP-TEST-JOHANNA-001"

    print(f"▶ Lees Excel: {EXCEL_PAD}")
    data = lees_excel(EXCEL_PAD, rapport_id)

    out = f"/mnt/user-data/outputs/{data['rapport_ref']}.pdf"
    Path(out).parent.mkdir(parents=True, exist_ok=True)

    print(f"▶ Genereer rapport voor {data['client_name']}")
    generate_rapport(data, out)
    print("✓ Klaar!")